<?php
declare(strict_types=1);
require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$csrf=email_admin_csrf();$error='';
$blank=['schemaVersion'=>2,'nodes'=>[['id'=>'trigger_1','type'=>'trigger','x'=>120,'y'=>140,'config'=>['label'=>'Início do fluxo','event'=>'INSCRITO','filter'=>'','advanceDuration'=>1,'advanceUnit'=>'hours']]],'edges'=>[],'viewport'=>['x'=>80,'y'=>60,'zoom'=>1]];
if($_SERVER['REQUEST_METHOD']==='POST')try{email_check_csrf();$action=(string)($_POST['action']??'create');if($action==='create'){$st=$pdo->prepare("INSERT INTO email_flows(name,status,draft_graph_json,created_by) VALUES(:n,'draft',:g,:a)");$st->execute(['n'=>trim((string)$_POST['name'])?:'Nova automação','g'=>json_encode($blank,JSON_UNESCAPED_UNICODE),'a'=>$_SESSION['equipe_nome']??'Administrador']);header('Location: email_fluxo.php?id='.$pdo->lastInsertId());exit;}$id=(int)$_POST['id'];if($action==='toggle')$pdo->prepare("UPDATE email_flows SET status=IF(status='active','paused','active') WHERE id=:id AND current_version_id IS NOT NULL")->execute(['id'=>$id]);}catch(Throwable $e){$error=$e->getMessage();}
$flows=$pdo->query("SELECT f.*,(SELECT version_number FROM email_flow_versions v WHERE v.id=f.current_version_id) version_number,(SELECT COUNT(*) FROM email_messages m WHERE m.flow_id=f.id) sent,(SELECT COUNT(*) FROM email_messages m WHERE m.flow_id=f.id AND m.delivered_at IS NOT NULL) delivered,(SELECT COUNT(*) FROM email_messages m WHERE m.flow_id=f.id AND m.first_clicked_at IS NOT NULL) clicks FROM email_flows f ORDER BY f.updated_at DESC")->fetchAll(PDO::FETCH_ASSOC)?:[];
$menu='email_marketing';$page_title='Automações de e-mail';include __DIR__.'/_header.php';echo email_admin_styles();
?><div class="em"><div class="em-head"><div><h1>Automações</h1><p class="text-muted">Jornadas automáticas com a mesma base de eventos das notificações do aplicativo.</p></div></div><?=email_admin_nav('flows')?><?php if($error):?><div class="em-msg em-error"><?=email_h($error)?></div><?php endif?><section class="em-card"><form method="post" class="em-actions"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input name="name" placeholder="Nome da automação" required><button class="btn btn-primary">+ Criar novo fluxo</button></form></section><section class="em-card"><div class="em-table"><table><thead><tr><th>Automação</th><th>Status</th><th>Versão</th><th>Enviados</th><th>Entregues</th><th>Cliques</th><th>Atualização</th><th></th></tr></thead><tbody><?php foreach($flows as $f):?><tr><td><strong><?=email_h($f['name'])?></strong><div class="text-muted"><?=email_h($f['description']??'')?></div></td><td><span class="em-pill"><?=email_h($f['status'])?></span></td><td><?=$f['version_number']?'v'.(int)$f['version_number']:'-'?></td><td><?=(int)$f['sent']?></td><td><?=(int)$f['delivered']?></td><td><?=(int)$f['clicks']?></td><td><?=email_h(date('d/m/Y H:i',strtotime($f['updated_at'])))?></td><td class="em-actions"><a class="btn btn-ghost btn-xs" href="email_fluxo.php?id=<?=(int)$f['id']?>">Editar</a><?php if($f['current_version_id']):?><form method="post"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=(int)$f['id']?>"><button class="btn btn-ghost btn-xs"><?=$f['status']==='active'?'Pausar':'Ativar'?></button></form><?php endif?></td></tr><?php endforeach?><?php if(!$flows):?><tr><td colspan="8">Nenhuma automação criada.</td></tr><?php endif?></tbody></table></div></section></div><?php include __DIR__.'/_footer.php';
